using System;
using Microsoft.Azure.WebJobs;
using Microsoft.Extensions.Logging;
using Microsoft.AspNetCore.Http;

public static class HttpTriggerCSharp
{
    [FunctionName("HttpTriggerCSharp")]
    public static void Run([HttpTrigger(AuthorizationLevel.Anonymous, "get", "post", Route = null)] HttpRequest req, ILogger log)
    {
        try 
        {    
            // Log HTTP request headers
            foreach (var header in req.Headers)
            {
                log.LogInformation("Header: {0}, Value: {1}", header.Key, header.Value);
            }
        
            // Log HTTP request body content
            string requestBody = new StreamReader(req.Body).ReadToEnd();
            log.LogInformation("Request Body: {0}", requestBody);
          
            // Log database queries with parameters (This will depend on your specific requirements, this is just a generic example)
            var sqlQuery = "SELECT * FROM users WHERE Id = @Id"; 
            var parameter = new SqlParameter("@Id", user.id);
            
            log.LogInformation($"Executing SQL Query: {sqlQuery} with parameters: {parameter}");
        
        } 
        catch (Exception ex) 
        {
           // Log exception details for debugging production issues
           log.LogError("Exception occured while processing request", ex);  
        }   
    }
}
